#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
#define _i128 __int128
using namespace std;
const int N = 2005;
int T,n,c,p,cnt,lth,sum,siz;
vector<string> A,B,C,D,emp,ans[N];
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}

int main(){
    T=read();
    while(T--){
        n=read(),c=read(),p=read();
        A=emp,B=emp,C=emp,D=emp;

        for(int i=1;i<=n;i++){
            string nam,o;cin>>nam>>o;
            if(o[0]=='n')A.pb(nam);
            else if(o[0]=='i')B.pb(nam);
            else if(o[0]=='t')C.pb(nam);
            else D.pb(nam);
        }

        siz=p+min(p,(int)(D.size()));

        for(cnt=0,sum=0;cnt<siz&&A.size()&&B.size();sum+=2){
            ans[++cnt]=emp;
            ans[cnt].pb(A.back()),ans[cnt].pb(B.back());
            A.pop_back(),B.pop_back();
        }

        for(lth=cnt;cnt<siz&&A.size()>=2&&C.size();sum+=3){
            ans[++cnt]=emp;
            ans[cnt].pb(A.back()),ans[cnt].pb(C.back());
            A.pop_back(),C.pop_back();
            ans[cnt].pb(A.back()),A.pop_back();
        }

        for(;A.size()&&C.size()&&lth;sum++,lth--){
            ans[lth].pop_back();
            ans[lth].pb(C.back()),ans[lth].pb(A.back());
            A.pop_back(),C.pop_back();
        }

        for(;lth!=cnt&&A.size()&&c;sum++,c--)
            ans[cnt].pb(A.back()),A.pop_back();

        cout<<sum+min(cnt/2,(int)(D.size()))<<"\n";

        for(int d=1;d<=cnt;d++){
            for(int i=0;i<ans[d].size();i++){
                if(i>2)cout<<",";
                if(i)cout<<" ";
                cout<<ans[d][i];
            }
            if(d<cnt){
                if(D.size()&&(d&1)){
                    cout<<" "<<D.back()<<" ";
                    D.pop_back();
                }else cout<<". ";
            }
        }if(cnt)cout<<".\n";
    }
    return 0;
}
